// frontend/src/App.tsx
import React, { useEffect, useState } from "react";
import {
  Box,
  Button,
  VStack,
  Heading,
  Text,
  Input,
  HStack,
  Alert,
  AlertTitle,
  AlertDescription,
} from "@chakra-ui/react";
import { ethers } from "ethers";
import { useWeb3 } from "./hooks/useWeb3";
import { useToken } from "./hooks/useToken";
import { useCooldown } from "./hooks/useCooldown";

const App: React.FC = () => {
  const { provider, signer, account, connectWallet } = useWeb3();
  const token = useToken(signer);

  const [balance, setBalance] = useState("0");
  const [cooldown, setCooldown] = useState(0);
  const [alert, setAlert] = useState("");

  const [recipient, setRecipient] = useState("");
  const [amount, setAmount] = useState("");

  // Fetch balance and cooldown whenever account changes
  useEffect(() => {
    if (!account) return;

    const fetchData = async () => {
      try {
        const bal = await token.balanceOf(account);
        setBalance(ethers.utils.formatUnits(bal, 18));

        const rem = await token.getRemainingCooldown(account);
        setCooldown(Number(rem));
      } catch (e) {
        console.error(e);
      }
    };

    fetchData();
  }, [account, token]);

  // Format cooldown
  const { formatted: cooldownFormatted } = useCooldown(cooldown);

  // Handle request tokens
  const handleRequest = async () => {
    if (!account) return;
    try {
      await token.requestTokens();
      setAlert("Tokens requested successfully!");
      const rem = await token.getRemainingCooldown(account);
      setCooldown(Number(rem));
    } catch (e: any) {
      setAlert(e?.reason || "Failed to request tokens");
    }
  };

  // Handle mint (owner only)
  const handleMint = async () => {
    if (!account) return;
    try {
      await token.mint(account, ethers.utils.parseUnits(amount || "0", 18));
      setAlert("Minted successfully!");
    } catch (e: any) {
      setAlert(e?.reason || "Mint failed");
    }
  };

  // Handle transfer
  const handleTransfer = async () => {
    if (!account) return;
    try {
      await token.transfer(
        recipient,
        ethers.utils.parseUnits(amount || "0", 18)
      );
      setAlert("Transfer successful!");
    } catch (e: any) {
      setAlert(e?.reason || "Transfer failed");
    }
  };

  return (
    <Box p={10}>
      <VStack spacing={6} align="stretch">
        <Heading textAlign="center">WEB3CXIV Token Dashboard</Heading>

        {/* Connect wallet */}
        {!account && <Button onClick={connectWallet}>Connect Wallet</Button>}

        {account && (
          <>
            <Text>
              <b>Account:</b> {account}
            </Text>
            <Text>
              <b>Balance:</b> {balance} CXIV
            </Text>

            {/* Faucet request */}
            {cooldown > 0 ? (
              <Text fontSize="sm" color="gray.600">
                Faucet cooldown: {cooldownFormatted}
              </Text>
            ) : (
              <Button colorScheme="teal" onClick={handleRequest}>
                Request Tokens
              </Button>
            )}

            {/* Transfer section */}
            <HStack spacing={2}>
              <Input
                placeholder="Recipient Address"
                value={recipient}
                onChange={(e) => setRecipient(e.target.value)}
              />
              <Input
                placeholder="Amount"
                value={amount}
                onChange={(e) => setAmount(e.target.value)}
              />
              <Button colorScheme="blue" onClick={handleTransfer}>
                Transfer
              </Button>
            </HStack>

            {/* Mint section (owner only) */}
            <HStack spacing={2}>
              <Input
                placeholder="Mint Amount"
                value={amount}
                onChange={(e) => setAmount(e.target.value)}
              />
              <Button colorScheme="purple" onClick={handleMint}>
                Mint
              </Button>
            </HStack>

            {/* Alert messages */}
            {alert && (
              <Alert status="info" borderRadius="md">
                <AlertTitle>Info</AlertTitle>
                <AlertDescription>{alert}</AlertDescription>
              </Alert>
            )}
          </>
        )}
      </VStack>
    </Box>
  );
};

export default App;
